import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

const gold = '#D4AF37'; // Classic Gold
const champagne = '#F3E5AB'; // Softer, matte gold/cream
const darkBackground = '#0A0A0A';

// --- COMPACT WIG STORE ---
const WigStore = () => {
  const categories = [
    {
      type: "Human Hair",
      items: [{ name: "Luxury Raw Cambodian", price: "85,000", desc: "14-inch frontal unit." }]
    },
    {
      type: "Premium Fibre",
      items: [{ name: "Sleek Straight Unit", price: "35,000", desc: "Heat resistant & pre-styled." }]
    },
    {
      type: "Hair Blend",
      items: [{ name: "Piano Wavy T-Closure", price: "25,000", desc: "24-inch high volume blend." }]
    }
  ];

  return (
    <div style={{ padding: '0 15px' }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ marginBottom: '15px' }}> {/* Reduced gap between types */}
          <h3 style={{ fontSize: '0.7rem', color: gold, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '8px', borderBottom: '1px solid #1a1a1a', paddingBottom: '4px' }}>
            {cat.type}
          </h3>
          {cat.items.map((item) => (
            <div key={item.name} style={{ display: 'flex', backgroundColor: '#111', borderRadius: '10px', marginBottom: '8px', padding: '10px', alignItems: 'center' }}>
              <div style={{ width: '55px', height: '55px', backgroundColor: '#000', borderRadius: '6px', marginRight: '12px' }}></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ fontSize: '0.8rem', margin: '0', color: '#fff' }}>{item.name}</h4>
                <div style={{ fontSize: '0.85rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
              </div>
              <button style={{ backgroundColor: gold, color: '#000', border: 'none', borderRadius: '15px', padding: '4px 12px', fontSize: '0.6rem', fontWeight: 'bold' }}>ADD</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
};

function App() {
  const [activeCategory, setActiveCategory] = useState('Small Chops');
  const [currentSlide, setCurrentSlide] = useState(0);

  const slides = [
    { title: "THE SMALL CHOPS", img: "https://via.placeholder.com/800x400/111111/D4AF37?text=SMALL+CHOPS" },
    { title: "THE HAIR EDIT", img: "https://via.placeholder.com/800x400/111111/D4AF37?text=WIGS" },
    { title: "OFFICE LUNCH", img: "https://via.placeholder.com/800x400/111111/D4AF37?text=LUNCH" }
  ];

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((s) => (s + 1) % slides.length);
    }, 4000);
    return () => clearInterval(timer);
  }, [slides.length]);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. COMPACT STICKY HEADER */}
      <header style={{ padding: '10px 15px', borderBottom: '1px solid #111', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: '#000', zIndex: 100 }}>
        <img src={Logo} alt="Logo" style={{ height: '25px' }} />
        <div style={{ display: 'flex', gap: '12px', fontSize: '1rem' }}>👤 🛒</div>
      </header>

      {/* 2. MATTE CHAMPAGNE HERO (Breathes, doesn't blind!) */}
      <div style={{ width: '100%', height: '160px', position: 'relative', overflow: 'hidden', background: `linear-gradient(to bottom, ${champagne} 0%, #000 100%)` }}>
        {slides.map((slide, index) => (
          <div key={index} style={{
            position: 'absolute', top: 0, left: 0, width: '100%', height: '100%',
            opacity: index === currentSlide ? 1 : 0,
            transition: 'opacity 1s ease-in-out'
          }}>
            <img src={slide.img} alt={slide.title} style={{ width: '100%', height: '100%', objectFit: 'cover', opacity: 0.4 }} />
            <div style={{ position: 'absolute', bottom: '20px', left: '20px' }}>
              <h2 style={{ fontSize: '1.2rem', color: champagne, fontWeight: '800', textTransform: 'uppercase', margin: 0 }}>{slide.title}</h2>
            </div>
          </div>
        ))}
      </div>

      {/* 3. TIGHT INFO BLOCK */}
      <div style={{ padding: '15px 20px 10px' }}>
        <h1 style={{ fontSize: '1rem', margin: '0' }}>Àmí by T - Lagos</h1>
        <p style={{ fontSize: '0.65rem', color: '#666', margin: '2px 0 10px' }}>● Opened · Closes 08:00 PM</p>
        <div style={{ display: 'flex', gap: '8px' }}>
          <button style={{ flex: 1, padding: '8px', borderRadius: '20px', border: 'none', backgroundColor: '#fff', color: '#000', fontWeight: 'bold', fontSize: '0.75rem' }}>Pickup</button>
          <button style={{ flex: 1, padding: '8px', borderRadius: '20px', border: '1px solid #222', backgroundColor: 'transparent', color: '#fff', fontSize: '0.75rem' }}>Delivery</button>
        </div>
      </div>

      {/* 4. COMPACT HORIZONTAL NAV */}
      <div style={{ display: 'flex', gap: '8px', overflowX: 'auto', padding: '10px 20px', scrollbarWidth: 'none' }}>
        {['Small Chops', 'Office Lunch', 'Wigs', 'About Us'].map((item) => (
          <button 
            key={item} 
            onClick={() => setActiveCategory(item)}
            style={{ 
              whiteSpace: 'nowrap', padding: '6px 15px', borderRadius: '20px', border: 'none',
              backgroundColor: activeCategory === item ? champagne : '#111',
              color: activeCategory === item ? '#000' : '#888',
              fontSize: '0.7rem', fontWeight: '700'
            }}
          >
            {item}
          </button>
        ))}
      </div>

      {/* 5. CONTENT AREA (NO LARGE GAPS) */}
      <main style={{ paddingBottom: '60px', marginTop: '-5px' }}>
        <h3 style={{ padding: '0 20px 10px', fontSize: '0.9rem', color: champagne }}>{activeCategory}</h3>
        <div style={{ transform: 'scale(0.98)', transformOrigin: 'top' }}> {/* Pulls content closer */}
          {activeCategory === 'Wigs' && <WigStore />}
          {activeCategory === 'Small Chops' && <Menu />}
          {activeCategory === 'Office Lunch' && <Lunch />}
        </div>
      </main>

    </div>
  );
}

export default App;
